# Configure Cross-Tenant Access Settings for a specific partner tenant
$partnerTenantId = "aaaabbbb-cccc-dddd-eeee-ffffgggghhh0"

# Add partner tenant
$partnerBody = @{
    tenantId = $partnerTenantId
} | ConvertTo-Json
Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners' \
    -Body $partnerBody -ContentType 'application/json'

# Allow inbound B2B from partner and trust their MFA
$inboundBody = @{
    b2bCollaborationInbound = @{
        usersAndGroups = @{ accessType = 'allowed'; targets = @(@{ target = 'AllUsers'; targetType = 'user' }) }
        applications   = @{ accessType = 'allowed'; targets = @(@{ target = 'AllApplications'; targetType = 'application' }) }
    }
    inboundTrust = @{
        isMfaAccepted = $true
        isCompliantDeviceAccepted = $false
        isHybridAzureADJoinedDeviceAccepted = $false
    }
} | ConvertTo-Json -Depth 6

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId/inboundTrust" \
    -Body $inboundBody -ContentType 'application/json'

# Create a Conditional Access policy requiring MFA for all guests
$caBody = @{
    displayName = 'Require MFA for B2B Guest Users'
    state = 'enabled'
    conditions = @{
        users = @{
            includeGuestsOrExternalUsers = @{
                guestOrExternalUserTypes = 'b2bCollaborationGuest,b2bCollaborationMember'
                externalTenants = @{ membershipKind = 'all' }
            }
        }
        applications = @{
            includeApplications = @('All')
        }
        clientAppTypes = @('browser','mobileAppsAndDesktopClients')
    }
    grantControls = @{
        operator = 'OR'
        builtInControls = @('mfa')
    }
} | ConvertTo-Json -Depth 8

New-MgIdentityConditionalAccessPolicy -BodyParameter ($caBody | ConvertFrom-Json)

# Create quarterly access review for all guest users
$arBody = @{
    displayName = 'Quarterly Guest User Access Review'
    descriptionForAdmins = 'Review all B2B guest users in the tenant'
    scope = @{
        query = '/users?$filter=userType eq ''Guest'''
        queryType = 'MicrosoftGraph'
    }
    reviewers = @(
        @{ query = '/users/admin@contoso.com'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        mailNotificationsEnabled = $true
        reminderNotificationsEnabled = $true
        justificationRequiredOnApproval = $true
        autoApplyDecisionsEnabled = $true
        defaultDecision = 'Deny'
        instanceDurationInDays = 14
        recurrence = @{
            pattern = @{ type = 'absoluteMonthly'; interval = 3; dayOfMonth = 1 }
            range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
        }
    }
} | ConvertTo-Json -Depth 8

New-MgIdentityGovernanceAccessReviewDefinition -BodyParameter ($arBody | ConvertFrom-Json)

# Remove guests who have not signed in for 90+ days
$cutoff = (Get-Date).AddDays(-90)
$staleGuests = Get-MgUser -Filter "userType eq 'Guest'" -All |
    Where-Object {
        ($_.SignInActivity.LastSignInDateTime -lt $cutoff) -or
        ($null -eq $_.SignInActivity.LastSignInDateTime)
    }

foreach ($guest in $staleGuests) {
    Write-Host "Removing stale guest: $($guest.UserPrincipalName) (last sign-in: $($guest.SignInActivity.LastSignInDateTime))"
    Remove-MgUser -UserId $guest.Id
}
Write-Host "Removed $($staleGuests.Count) stale guest accounts."
